#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(param);

my $cgi = new CGI;
my $log_dir = '/path/to/log/directory'; # Replace with actual log directory path

my $filename = param('logfile');
if (!$filename) {
    print "Content-Type: text/plain\n\n";
    print "No logfile specified.\n";
    exit;
}

my $file_path = "$log_dir/$filename";

# Check if the file exists and is readable
if (-e $file_path && -r $file_path) {
    open(my $fh, '<', $file_path) or die "Could not open file '$file_path' $!";
    
    print "Content-Type: text/plain\n\n";
    while (my $line = <$fh>) {
        print "$line";
    }
    close($fh);
} else {
    print "Content-Type: text/plain\n\n";
    print "File not found or not readable.\n";
}